typedef struct {
    int starting;
    int no_of_edges;
} Node;

kernel void BFS_1(global const Node* graph_nodes,
                  global const int* graph_edges,
                  global char* graph_mask,
                  global char* updating_graph_mask,
                  global const char* graph_visited,
                  global int* cost,
                  const int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (graph_mask[tid] == 1) {
            graph_mask[tid] = 0;
            int start = graph_nodes[tid].starting;
            int end = start + graph_nodes[tid].no_of_edges;

            for (int i = start; i < end; i++) {
                int id = graph_edges[i];
                if (graph_visited[id] == 0) {
                    cost[id] = cost[tid] + 1;
                    updating_graph_mask[id] = 1;
                }
            }
        }
    }
}

kernel void BFS_2(global char* graph_mask,
                  global char* updating_graph_mask,
                  global char* graph_visited,
                  global char* stop,
                  const int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (updating_graph_mask[tid] == 1) {
            graph_mask[tid] = 1;
            graph_visited[tid] = 1;
            *stop = 1;
            updating_graph_mask[tid] = 0;
        }
    }
}
